const d = $input.first().json;
const digits = (d.telefono || '').replace(/\D/g, '');
const tel10 = digits.slice(-10);
return [{
  json: {
    telefono_10: tel10,
    telefono_full: '52' + tel10,
    nombre_cliente: d.nombre_cliente || 'Cliente',
    mensaje_cliente: d.mensaje_cliente || '',
    mensaje_id: d.mensaje_id || ''
  }
}];

const prev = $('Normalizar Teléfono').first().json;
const cuentas = $input.first().json;
if (!Array.isArray(cuentas) || cuentas.length === 0) {
  return [{ json: { encontrada: false, telefono_full: prev.telefono_full, mensaje_cliente: prev.mensaje_cliente } }];
}
const c = cuentas[0];
const bucket = c.bucket || '1-30';
const comp = c.comportamiento_historico || 'regular';
let modelo;
if (bucket === '1-30') modelo = 'empatico';
else if (bucket === '31-60') modelo = (comp === 'malo') ? 'presion' : 'firme';
else modelo = 'presion';
return [{ json: { encontrada: true, cuenta: c, modelo, telefono_full: prev.telefono_full, mensaje_cliente: prev.mensaje_cliente } }];

const prev = $('Construir Prompt').first().json;
const gemini = $input.first().json;
const texto = gemini?.candidates?.[0]?.content?.parts?.[0]?.text
  || gemini?.candidates?.[0]?.content?.parts?.[0]?.text
  || 'En este momento no puedo procesar tu solicitud. Por favor llama al 800 de Libertad Financiera.';
return [{ json: { ...prev, respuesta_ia: texto.trim() } }];
